var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"프레데릭 도마.","JPN":"フレドレック・ドマ。","ENG":"Frederick Doma.","TWN":"弗雷德里克·多馬。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"의회는 만장일치로, 그대를 일족의 송곳니로 임명한다.","JPN":"議会は満場一致で、そなたを一族の戦士の牙に任命する。","ENG":"The council unanimously appoints you as the Fang of our tribe.","TWN":"議會一致決定，任命你為一族的獠牙。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그대는 신성한 의무에 따라 북대륙으로 떠나라.","JPN":"そなたは神聖なる義務に従い、北の大陸へと向かえ。","ENG":"Go north and fulfill your divine duty.","TWN":"依照聖務前往北方大陸吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그곳에서 잠들어 있는 잿더미의 여왕을 깨워라.","JPN":"そしてそこに眠っている灰の女王を目覚めさせるのだ。","ENG":"Awaken the Queen of Ashes from her slumber.","TWN":"然後去喚醒沉睡在那裡的灰燼女王。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"일족의 운명은 그대에게 달렸다.","JPN":"一族の運命はそなたにかかっている。","ENG":"The tribe's fate rests in your hands.","TWN":"家族的命運已然掌握在你的手中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 내 사랑하는 여동생. 오라버니가 돌아왔단다.","JPN":"ああ、愛する妹よ。兄さんが戻ってきた。","ENG":"Oh, my beloved little sister. I have returned.","TWN":"喔，我親愛的妹妹，哥哥回來了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L11_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"으… 그 말투 징그러워, 오빠.","JPN":"うう……その口調、気持ち悪いよ。兄さん。","ENG":"Ugh... Please don’t talk like that. It’s gross.","TWN":"呃…哥，你這語氣真噁心。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그리고 피냄새 나. 이상해.","JPN":"それに血の匂いがする。何か変。","ENG":"You reek of blood. Gross.","TWN":"而且你身上有血腥味，好奇怪。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그야 흡혈귀에게 피냄새가 나는 건 당연한 일이지.","JPN":"吸血鬼から血の匂いがするのは当たり前だろう？","ENG":"Vampires are supposed to smell of blood.","TWN":"在吸血鬼身上聞到血腥味是理所當然的吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"게다가 이 오빠는 전선에서 싸우는 일족의 전사잖니.","JPN":"それにこの兄は前線で戦っている一族の戦士だ。","ENG":"Plus, I'm a warrior who fought in the frontlines of battle for our tribe.","TWN":"而且哥哥我可是在前線作戰的家族戰士啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"인간 피냄새 뿐만이 아니니까 그렇지.","JPN":"でも、この血の匂い、人間だけじゃないよね？","ENG":"I’m saying it because it’s not just human blood that I smell.","TWN":"不僅僅是人類的血腥味。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"의회 어르신들이 또 의식이랍시고 염소 피라도 뒤집어씌운 거야?","JPN":"議会の人たちがまた儀式とか言ってヤギの血でも浴びせた？","ENG":"Did the council elders pour goat blood over you as a ritual or something?","TWN":"議會的老傢伙們又在搞什麼儀式，難道又要澆羊血嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 역시 동생의 코는 못 속이겠구나.","JPN":"ふふ、やはり我が妹の鼻は騙せないな。","ENG":"Hah hah, your sense of smell is as keen as ever.","TWN":"呵呵，果然瞞不過你的鼻子啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘은 이 오빠가 오는 도중에 늑대인간의 우두머리와 결투를 벌였단다.","JPN":"今日はこの兄が、ここに来る途中でライカンスロープの頭と決闘をしたんだ。","ENG":"Your big brother fought an alpha lycanthrope on his way back home.","TWN":"今天我回來的路上和狼人首領決鬥了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"와앗! 정말…?!","JPN":"わあっ！　本当に……！？","ENG":"Whaaat?! Really...?!","TWN":"哇啊！真的…？！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"어땠어?! 강했어?!","JPN":"どうだった！？　強かった！？","ENG":"How was it? Strong?!","TWN":"怎麼樣？！很強嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론! 그 뾰족한 손톱이 옷깃을 스쳤을 땐 나도 아찔했거든!","JPN":"もちろん！　あの鋭い爪が服をかすめた時には私もぞっとしたんだ！","ENG":"Of course! Her razor-sharp claws had me on my toes!","TWN":"當然！那尖銳的爪牙擦過衣領時，我真的嚇了一跳！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"아하하, 만월의 영기를 받은 늑대인간이랑 싸우다니!","JPN":"あはは、満月の霊気を浴びたライカンスロープと戦うなんて！","ENG":"Ah hah hah! You fought a lycanthrope under a full moon?!","TWN":"啊哈哈，竟然和吸收了月圓靈氣的狼人戰鬥！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"역시 오라버니는 제정신이 아냐! 굉장해!","JPN":"やっぱり兄さんは正気じゃないね！　すごい！","ENG":"You’re crazy! But also amazing!","TWN":"哥哥果然不正常！太厲害了！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"얼른 얘기 더 들려줘!","JPN":"早くもっと聞かせて！","ENG":"C’mon! Tell me more!","TWN":"快快，再講點這樣的事！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"흐음, 유스티스라고 하는구나.","JPN":"ふーん、ユースティスって言うんだね。","ENG":"Hmm... So her name is Eustis.","TWN":"嗯，原來叫尤思蒂斯啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"혼혈답게 제법 인간다운 이름이네.","JPN":"混血らしく、結構人間ぽい名前じゃない。","ENG":"I guess it fits as she’s half-human...","TWN":"不愧是混血，名字還蠻像人類的嘛。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그럼 다음에 또 오빠와 결투하러 찾아오는 거야?","JPN":"じゃあ、後でまた兄さんと決闘しにやってくるの？","ENG":"Then is she going to track you down and ask for a rematch?","TWN":"那之後還會來找哥哥決鬥嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그래. 아직 어린 소녀였으니까, 분명 다음 번엔 더 강해져 있겠지.","JPN":"ああ。まだ少女だったから、きっと今度はもっと強くなってるだろう。","ENG":"I hope so. She’s still young, but she might even be able to beat me next time we meet.","TWN":"會吧。畢竟她還是個小女孩，之後一定會變得更強的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"너도 기대되지 않니?","JPN":"あなたも楽しみでしょう？","ENG":"I can’t wait! Don’t you agree?","TWN":"你也很期待吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"아아, 나도 싸우고 싶다. 누워서 이야기만 듣는 건 지긋지긋해.","JPN":"あ～あ、私も戦いたい。寝込んで話ばっかり聞いているのはもうコリゴリだよ。","ENG":"Ugh... I wanna fight too. I’m tired of only hearing your stories.","TWN":"啊啊，我也想戰鬥。躺著聽故事真是無聊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…콜록, 콜록!","JPN":"……ゲホッ、ゲホッ！","ENG":"...Cough! Cough!","TWN":"…咳咳，咳咳！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 그렇지. 오늘은 너에게 줄 선물을 가져왔단다.","JPN":"あ、そうだ。今日はプレゼントを持ってきたんだ。","ENG":"Oh, that’s right! I brought a little present for you.","TWN":"啊，對了。我今天有帶禮物要給你。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"이건…? 혈석 반지잖아?","JPN":"これは……？　血石の指輪？","ENG":"Isn’t this... a Bloodstone Ring?","TWN":"這是…？血鑽戒？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"엄청 귀한 건데… 오빤 이걸 어떻게 구했어?","JPN":"とても貴重なものなのに……兄さん、どうやってこれを手に入れた？","ENG":"Aren’t these hard to find? Where did you even get one?","TWN":"這麼珍貴的東西…哥哥你是怎麼弄到的？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 우리 영지를 침공했던 공작이 손에 끼고 있던 거란다.","JPN":"ふふ、私たちの領地を攻めてきた公爵が指につけていたものだよ。","ENG":"Hah hah... I got it from the foolish Duke who tried to take away our lands.","TWN":"呵呵，這是那個入侵我們領地的公爵戴在手上的東西。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그 욕심 많은 인간이 이런 것도 베풀 줄 알더구나.","JPN":"あの欲張りの人間がこんなものを喜んでくれるなんてね。","ENG":"I didn’t know a greedy human like him knew how to share this precious thing.","TWN":"沒想到那個貪心的人類竟然也會施捨這種東西。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"흐음, 보나마나 대결에서 살려주는 대가로 받았겠지.","JPN":"ふーん、どうせ対決で生かせてやる対価でもらったんでしょう？","ENG":"Hmm... I’m guessing you made a deal in exchange for his life?","TWN":"嗯，這是哥哥在對決中對他手下留情得到的代價吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"진짜 흡혈귀라면 인간은 하나도 살려 두지 않았을 텐데, 오빠는 쓸데없이 자비롭다니까.","JPN":"本当の吸血鬼なら人間は1人も生かせてやらないはずなのに、兄さんってばもう優しいんだから。","ENG":"A real vampire would’ve never let any human go free. You can be a big softie sometimes.","TWN":"如果是真的吸血鬼，那些人類沒有一個能活著回去，哥哥你就是太仁慈了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그런 누명을 씌우다니! 이래봬도 오빠는 피도 눈물도 없는 잔혹한 결투가로 유명하단다.","JPN":"そんな濡れ衣を着せるなんて！　こう見えても兄さんは血も涙もない残酷な決闘者で有名なんだよ。","ENG":"Absurd! Your big brother is infamous as the heartless duelist!","TWN":"那你可是冤枉我了！要知道，哥哥可是以沒血沒淚的決鬥者而聞名的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그 별명, 분명 오빠랑 만나본 적도 없는 녀석이 지었을 거야.","JPN":"そのあだ名、きっと兄さんと会ったことないやつがつけてるね。","ENG":"I’m pretty sure whoever coined you that nickname never met you once.","TWN":"那個外號，肯定是從來沒見過哥哥的傢伙取的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 아무튼 꼭 이 반지를 가지고 있으렴. 그러면 네 병도 좀 나아질 거란다.","JPN":"ふふ、とにかくこの指輪を持ってて。そうしたらあなたの病気も少しはよくなるはずだから。","ENG":"Hah hah. Anyway, make sure you always wear this ring. It’ll help with your disease.","TWN":"呵呵，總之一定要帶上這枚戒指。這樣你的病情也會好轉的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"흥, 뭐야? 그게?","JPN":"ふん。何よ、それ。","ENG":"Hmph! You really think I’ll believe that?","TWN":"哼，什麼嘛？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"혈석이 검은 역병을 막아준다는 건 거짓말쟁이 인간들이 만든 미신이잖아.","JPN":"血石が黒い疫病から守ってくれるって、嘘つきの人間たちがでっち上げた迷信でしょう？","ENG":"Bloodstones preventing the Black Plague is just something the humans made up!","TWN":"血石能抑制黑死病就是人類編織的謊言。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠는 정말 순진하다니까.","JPN":"兄さんって本当に純粋なんだから。","ENG":"You can be so gullible sometimes, you know.","TWN":"哎呀，你真是天真。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"차라리 심장을 먹으면 그 사람 영혼이 함께 옮겨간다는 흡혈귀들의 전설을 믿지 그래?","JPN":"いっそ心臓を食べるとその人の魂が一緒に移るって吸血鬼の伝説を信じた方がましだね。","ENG":"How’s that any different from the vampiric legend of eating someone’s heart transfers their soul into you?","TWN":"乾脆相信吸血鬼的傳說吧。說吃了心臟後，就能連同那個人的靈魂一起轉移。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"이렇게 시름시름 앓다가 허무하게 죽을 바엔…","JPN":"こうやって病気で苦しんで、虚しく死ぬくらいだったら……","ENG":"So instead of suffering in pain and dying...","TWN":"這樣病懨懨地死去，還不如…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"차라리 오빠가 내 심장을…","JPN":"いっそ兄さんが私の心臓を……","ENG":"If you could eat my heart...","TWN":"不如哥哥把我的心臟…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런! 벌써 시간이 이렇게 되다니.","JPN":"おっと！　もうこんな時間か。","ENG":"Oh my! Look at the time.","TWN":"糟糕！時間都這麼晚了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"박쥐들도 모두 잠에 들 시간이란다, 동생아.","JPN":"コウモリもみんなおやすみの時間だよ。","ENG":"Even the bats must be tired at this hour, little sister.","TWN":"連蝙蝠們都該睡了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"잠을 잘 자야 병도 낫지 않겠니?","JPN":"ちゃんと寝ないと病気も治らない。","ENG":"You need your rest, so you have the strength to fight off the disease, no?","TWN":"好好睡覺病才會好喔。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"뭐래. 갑자기 애 취급이나 하고.","JPN":"何？　いきなり子ども扱いして。","ENG":"Ugh... You’re treating me like a little kid again.","TWN":"說什麼呢？突然把我當小孩。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠야말로 하루 빨리 북대륙으로 떠나야 할 때에 계속 이러고 있어도 되는 거야?","JPN":"兄さんこそ一日でも早く北の大陸に行かないといけないのに、ずっとこうやっててもいいの？","ENG":"Hey, don’t you have to start your journey up north soon? Aren’t you already behind schedule?","TWN":"哥哥你才是，該早早動身前往北方大陸了，還在這裡磨蹭嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음? 너도 알고 있었던 거니?","JPN":"うん？　あなたも知っていたのかい？","ENG":"Hmm? You know about that too?","TWN":"嗯？你也知道了啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"의회 어르신들한테 떠나기 싫다고 고집 부렸다며?","JPN":"議会の人たちに行きたくないって我がまま言ってたらしいじゃない。","ENG":"I heard from the elders that you’re being stubborn and refusing to go.","TWN":"聽說你跟議會的長老們說你不想離開？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"바보 겁쟁이. 일족을 대표하는 전사가 왜 이리 책임감이 없어?","JPN":"バカ、臆病者。一族を代表する戦士なのに、責任感がなさすぎじゃない。","ENG":"Stupid coward. How can the warrior representing our tribe be so irresponsible?","TWN":"笨蛋膽小鬼。作為代表家族的戰士，怎麼這麼沒有責任感？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 동생아. 의회 어르신들은 지혜롭지만 세상의 모든 답을 아는 건 아니란다.","JPN":"ふふ。議会の老人達は知恵があるけど、世界のすべての答えを知ってるわけではない。","ENG":"Hah hah, oh my sister... The elders may be wise, but they don’t have all the answers to the universe.","TWN":"呵呵，我的妹妹啊。議會的長老們雖然聰明，但並不是什麼都知道。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"애초에, 잿더미의 여왕이라는 건 오래된 전설일 뿐이야.","JPN":"そもそも、灰の女王というのは古い伝説なだけ。","ENG":"Take the Queen of Ashes, for instance, it’s nothing but an ancient legend.","TWN":"本來，灰燼女王只是一個古老的傳說而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"설사 그게 사실이라고 해도 그녀가 우리 일족을 도와줄 거란 보장 같은 건 없단다.","JPN":"もしそれが事実だとしても、彼女が我が一族を助けてくれるという保証などない。","ENG":"Even if it were true, we have no guarantee that she’ll even help us.","TWN":"即使那是真的，也不能保證她會幫助我們家族。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"검은 역병을 해결할 능력이 있는지는 더더욱 확신할 수 없지.","JPN":"黒い疫病を解決する能力があるかは尚更だ。","ENG":"Plus, we can’t be sure she even has the ability to cure the Black Plague.","TWN":"更無法確定是否有能力解決黑死病。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"게다가 넌 우리 일족에 이제 몇 없는 순수한 피를 가진 고위 흡혈귀란다.","JPN":"それに、あなたは我が一族に数少ない純粋な血を持っている高位の吸血鬼。","ENG":"Besides, you’re one of the few remaining pure-blooded high-class vampires in our tribe.","TWN":"而且你是我們家族中為數不多擁有純正血統的高階吸血鬼。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그런 널 두고 내가 어디로 가겠니?","JPN":"そんなあなたをおいて、どこにも行けと言うのだい？","ENG":"So, where would I go leaving you alone here?","TWN":"我怎麼會丟下你一個人走呢？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠 하나 없다고 해서 고작 인간들에게 당하진 않아.","JPN":"兄さんがいないからって、人間にやられたりはしないよ。","ENG":"Just because you’re not here, doesn’t mean I’ll get taken by some mere humans.","TWN":"就算沒有哥哥，我也不會被區區人類打敗。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그리고 북대륙에 가면 최소한 희망은 품어볼 수 있는 거잖아.","JPN":"それに北の大陸に行くと、少なくとも希望は持てるんじゃない？","ENG":"And also, if you go up north, there’s at least some hope we can look forward to.","TWN":"而且去北方大陸的話，至少還有一絲希望。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠는 이 동생이 그렇게 되고 싶다고 노랠 부르던 일족의 송곳니가 된 거라고.","JPN":"兄さんは私がなりたかった一族の戦士の牙になったの。","ENG":"You know, you’re living my dream right now becoming the Fang of our tribe.","TWN":"哥哥，你現在可是我做夢都想當的一族的獠牙呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그러니까 좀, 내 몫까지 열심히 해.","JPN":"だから、私の分までちゃんと頑張ってよ。","ENG":"So, why don’t you do it for me?","TWN":"所以說，你要連我那份一起努力啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"여기서 내 걱정이나 하고 있어봤자… 검은 역병은 계속해서 우리 일족을 갉아먹을 뿐이니까.","JPN":"ここで私のことを心配してたって……黒い疫病は私たちの一族をずっといじめるだけだから。","ENG":"If you sit on your hand and do nothing... the Black Plague will just keep spreading deeper into our tribe.","TWN":"留在這裡擔心我也沒用…黑死病只會繼續吞噬我們的族人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"저 멀리 북대륙에는 위대한 자가 얼어붙은 강철의 성채에 잠들어 있으니.","JPN":"かの北の大陸には、偉大なる者が凍り付いた鋼の城塞に眠っている。","ENG":"The great one sleeps in the castle of frozen steel in the far north...","TWN":"在遙遠的北方大陸，有一位偉大的人物沉睡在冰封的鋼鐵堡壘中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀를 깨워 힘을 빌린다면, 이 세상에 만연한 검은 역병의 근원을 제거할 수 있을지도 모른다.","JPN":"彼女を起こし力を借りるなら、この世に漫然としている黒い疫病の根源を除去できるかもしれない。","ENG":"By waking her and borrowing her powers, it might be the only way to rid the cause of the Black Plague once and for all.","TWN":"如果喚醒她並借助她的力量，或許能夠消除這個世界上蔓延的黑死病根源。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"의회 어르신들의 말씀처럼 일족을 구원할 수 있을지도 모르지.","JPN":"議会の老人たちの話のように、一族を救い出せるかもしれない。","ENG":"Then, I’ll be able to save my tribe like the elders have said.","TWN":"也許就像議會長老們所說的那樣，可以拯救整個家族。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그 길은…","JPN":"だけど、その道は……","ENG":"But that also means...","TWN":"但那條路…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"기억나? 오빠가 여기 처음으로 마차를 타고 온 날.","JPN":"覚えてる？　兄さんが初めてここに馬車に乗って来た日。","ENG":"Hey, do you remember the first time you came here on a wagon?","TWN":"記得嗎？哥哥第一次坐馬車來到這裡的那天。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"인간 여자가 낳은 놈을 가문에 들여왔다고 해서 다들 난리도 아니었지.","JPN":"人間の女が産んだやつを家門に迎え入れたって、みんな大騒ぎしてたよね。","ENG":"Everyone was outraged that a human woman's child had been brought into the family.","TWN":"因為把一個人類女人所生的傢伙帶進家族，大家都鬧翻天了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아버지께선 공정함을 중요하게 여기는 분이셨으니까. 내게도 기회를 주셨을 뿐이란다.","JPN":"お父様は公正を大事に思っていた方だったから。私にもチャンスを与えてくださっただけだよ。","ENG":"Father always puts fairness above all else. That’s why he gave me a chance.","TWN":"父親是個非常重視公平的人，他只是給了我一個機會而已。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"훗, 그때 난 오빠라고 부르기도 싫다고 고집을 부렸지.","JPN":"ふふっ、あの時の私は兄さんって呼びたくもないって駄々こねてたし。","ENG":"Heh, I insisted on not acknowledging you as my older brother back then.","TWN":"哼，那時候我還固執地說不想叫你哥哥呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"결투도 몇 번씩이나 져서, 분해서 잠도 못 잤어. 멋대로 장원 밖을 뛰쳐나가기도 하고.","JPN":"決闘でも何度も負けて、悔しくてちゃんと眠れなかったなあ。勝手に荘園の外に飛び出したりもして。","ENG":"I also couldn’t sleep because I was so angry to lose the duels several times, and I’d used to sneak out of the village.","TWN":"決鬥也輸了好幾次，氣得睡不著覺。還擅自跑出莊園。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아아, 물론 기억하고 말고.","JPN":"ああ、もちろん覚えている。","ENG":"Ahh. I remember that too.","TWN":"啊啊，當然記得了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"스물 한 번째로 진 날 밤, 넌 전사의 시험을 치르겠다며 뛰쳐나갔었지.","JPN":"21回負けた日の夜、あなたは戦士の試練を乗り越えるって飛び出た。","ENG":"After our twenty-first duel, you ran out, saying you wanted to take the warrior test.","TWN":"在第二十一打輸的夜晚，你說要接受戰士的試煉，然後就衝了出去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그날 들개 무리한테 둘러싸여서 죽을 뻔했을 때, 오빠가 구하러 와주지 않았더라면…","JPN":"あの日に野良犬の群れに囲まれて死にそうになったけど、兄さんが助けに来てくれなかったら……","ENG":"If you didn’t come to save me from the pack of hounds...","TWN":"那天被野狗群包圍差點死掉的時候，如果不是哥哥來救我的話…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"난 아직까지도 오빠를 남으로 생각하고 있었을 지도 몰라.","JPN":"私は今でも兄さんを他人だと思っていたかもしれない。","ENG":"I don’t know. But I might not still think of you as my real brother.","TWN":"我可能到現在還把哥哥當成外人。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그럴 리가. 우리 동생처럼 정 많고 사랑스러운 흡혈귀는 없단다.","JPN":"そんなはずは。あなたのように優しくて愛おしい吸血鬼はいない。","ENG":"Nonsense. There’s no vampire on earth that’s kindhearted and loving as you.","TWN":"怎麼可能。像我妹妹這樣溫暖又可愛的吸血鬼是不存在的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"계기야 어떻게 됐든, 나와는 지금쯤 사이좋은 오누이가 되었을 거야.","JPN":"きっかけがどうであろうと、私とは今頃仲良い兄妹になっていたはずだよ。","ENG":"Whatever the case may be, I’m sure you think of me as your brother now.","TWN":"不管怎麼樣，我們現在應該已經是感情很好的兄妹吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠와 사냥을 다니고 친해지면서, 난 언제나 즐거움과 함께 두려움을 안고 있었어.","JPN":"兄さんと狩りに出て仲良くなって、私はいつも楽しさと怖さが隣り合わせだった。","ENG":"I liked going hunting with you and getting to know you. But I also had this nagging fear in the back of my mind.","TWN":"和哥哥一起狩獵，關係慢慢變親，我心中總是既充滿快樂，又懷著恐懼。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"사람 피가 섞인 흡혈귀의 수명은 우리보다 휠씬 짧으니까.","JPN":"人の血が混ざった吸血鬼の寿命は、私たちよりずっと短いから。","ENG":"You know, because half-bloods have a much shorter lifespan than other vampires.","TWN":"混有人類血脈的吸血鬼壽命比我們短很多。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그전까진 가족과 그런 식으로 이별할 수도 있다는 걱정은 해본 적이 없었거든.","JPN":"それまでは家族とそんな風にお別れになるなんて心配したこともなかった。","ENG":"I never worried about having to say goodbye to a family member in this way before you.","TWN":"在那之前，我從未想過會以那種方式與家人告別。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그래서, 내가 이렇게 된 게 오히려 다행이라고 생각해.","JPN":"だから、私がこうなったのがむしろよかったって思う。","ENG":"But now, I think that my getting this disease is a good thing in disguise.","TWN":"所以，我反而覺得這樣也算是慶幸。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠가 다른 인간처럼 나약해지고 죽어가는 걸, 적어도 내 눈으로 볼 일은 없어졌으니까.","JPN":"兄さんが他の人間のように弱くなって死んでいく姿を、少なくとも私の目で直接見ることはなくなったからね。","ENG":"Now, I don’t have to see you grow old and weak like other humans.","TWN":"至少我不用親眼看到哥哥像其他人類一樣死去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"어때? 나 제법 인간처럼 이기적인 생각도 잘하지?","JPN":"どう？　私、結構人間みたいに勝手なこと考えられるでしょう？","ENG":"So, what do you think? I’m good at being selfish like a human too, right?","TWN":"怎麼樣？我現在是不是也跟人類一樣，想法很自私？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 그렇구나.","JPN":"ふふ、そうだね。","ENG":"Hah hah, I guess so.","TWN":"呵呵，好像確實是。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"좀 더 이기적인 말 해도 돼?","JPN":"もっと勝手なこと言ってもいい？","ENG":"Can I be a little bit more selfish today?","TWN":"我可以再自私一點嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그야 물론이란다. 그래봐야 이 오빠를 따라잡진 못하겠지만 말이야.","JPN":"もちろんだよ。でも、この兄に追いつくことはできないだろうけどね。","ENG":"Of course. But you’ll never reach my level of selfishness.","TWN":"那當然，不過你還是追不上哥哥我的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"싸우고 싶어.","JPN":"戦いたい。","ENG":"I want to fight.","TWN":"我想戰鬥。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"지금은 이 망할 병 때문에 누워있지만, 나도 오빠처럼… 그 늑대인간 소녀처럼…","JPN":"今はこのクソ病気のせいで寝込んでるけど、私も兄さんみたいに……あのライカンスロープの少女みたいに……","ENG":"Even though I’m stuck here because of this disease, I want to fight... Like you and that lycanthrope girl...","TWN":"雖然現在因為該死的病躺在這裡，但我也想像哥哥那樣…像那個狼人少女那樣…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"다시 한번 전사답게, 마음껏 피를 흘리며 싸워보고 싶어.","JPN":"もう一度戦士らしく、思いっきり血を流しながら戦ってみたい。","ENG":"I want to fight to my heart’s content like a real warrior.","TWN":"我想再一次像戰士一樣，盡情戰鬥，盡情流血。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"오빠는 그 부탁 못 들어주겠지?","JPN":"兄さんはこの願い、聞いてくれることはできないよね？","ENG":"But you can’t do anything about that, right?","TWN":"哥哥應該不會答應吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"나의 옛 어머니께선, 가끔씩 하늘에 대고 기도라는 걸 올리곤 하셨지.","JPN":"私の実の母は、たまに空に向かってお祈りというのを捧げてた。","ENG":"My mother... She used to look up to the sky and pray.","TWN":"我母親過去常常向著天空祈禱。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이기적인 인간들은 그렇게 보이지 않는 곳을 향해 기도를 하고…","JPN":"自分勝手な人間はそうやって見えないところに向かってお祈りをし……","ENG":"Humans are selfish, as they start into nothingness...","TWN":"自私的人類就是這樣，經常向看不見的地方祈禱…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무런 대가도 없이 소원이 이루어지는 기적을 바란단다.","JPN":"何の対価もなく願いが叶う奇跡を求めるんだ。","ENG":"and pray for a miracle without ever paying the price.","TWN":"希望不需要付任何代價就能實現自己的願望。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"나도 다른 인간들처럼… 기적을 원해.","JPN":"私も他の人間たちのように……奇跡がほしい。","ENG":"But like those humans... I too, want a miracle.","TWN":"我也像其他人類一樣…渴望奇蹟。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"소원… 빌어도 될까?","JPN":"願い事……してもいいかな？","ENG":"Then can I... make a wish?","TWN":"可以…許願嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이기적인 네 오빠는 이미 동생의 소원이 이루어지길 바라고 있단다.","JPN":"自分勝手なこの兄は、すでにあなたの願いが叶うことを望んでいるんだよ。","ENG":"This self-centered brother of yours already hopes that your wish will come true.","TWN":"自私的哥哥一直希望妹妹的願望可以實現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};